"""Dataset wrapper for converted SuiteSparse matrices with per-graph normalization."""

import numpy as np
import torch
from torch_geometric.data import Data, Dataset


class SuiteSparseDataset(Dataset):
    """Loads .npy files generated by convert_suitesparse.py.

    Normalizes each graph so that max(|A|) = 1.0 for training stability.
    """

    def __init__(self, data_dir, use_data_num=None):
        super().__init__()
        self.graphs = []
        self._load(data_dir)
        if use_data_num is not None and use_data_num > 0:
            self.graphs = self.graphs[:use_data_num]

        # Set dataset properties from first graph
        g0 = self.graphs[0]
        self.node_attr_dim = g0.x.shape[-1]
        self.edge_attr_dim = g0.edge_attr.shape[-1]
        self.num_edges = g0.edge_attr.shape[0]
        self.output_dim = 1
        self.dirichlet_idx = 3
        self.b_dim = g0.x.shape[0]

    def _load(self, data_dir):
        import os
        files = sorted([f for f in os.listdir(data_dir) if f.endswith('.npy')])
        for f in files:
            path = os.path.join(data_dir, f)
            data_list = np.load(path, allow_pickle=True)
            for d in data_list:
                # edge_attr layout from converter: [edge_len, value, structural_flag]
                # Model expects value in last channel: [edge_len, structural_flag, value]
                ea = torch.from_numpy(d['edge_attr']).float()
                ea = torch.stack([ea[:, 0], ea[:, 2], ea[:, 1]], dim=-1)

                # Normalize matrix entries to [-1, 1] for training stability
                edge_vals = ea[:, -1]
                max_abs = edge_vals.abs().max().item()
                scale = max(1.0, max_abs)
                ea[:, -1] = ea[:, -1] / scale

                diag = torch.from_numpy(d['diag']).float() / scale
                rhs = torch.from_numpy(d['rhs']).float() / scale
                y = torch.from_numpy(d['y']).float() / scale

                g = Data(
                    x=torch.from_numpy(d['x']).float(),
                    edge_attr=ea,
                    edge_index=torch.from_numpy(d['edge_index']).long(),
                    y=y,
                    rhs=rhs,
                    u=torch.from_numpy(d['u']).float(),
                    u_next=torch.from_numpy(d['u_next']).float(),
                    diag=diag,
                    r=torch.from_numpy(d['r']).float(),
                )
                # Fix: converter marks all nodes as interior (1.0), but model
                # treats channel 3 as Dirichlet flag (1.0 = boundary).
                # SuiteSparse matrices have no Dirichlet boundaries.
                g.x[:, 3] = 0.0
                self.graphs.append(g)

    def __len__(self):
        return len(self.graphs)

    def __getitem__(self, idx):
        return self.graphs[idx]
